#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    rfl::Rename<"SNo", sqlgen::PrimaryKey<std::string>> sno;
    rfl::Rename<"SName", std::string> sname;
    rfl::Rename<"Sex", std::optional<int>> sex = 1;
    rfl::Rename<"Birthday", std::optional<std::string>> birthday;
    rfl::Rename<"Major", std::optional<int>> major;
    rfl::Rename<"Scorses", std::optional<float>> scorses = 0.0f;
    rfl::Rename<"Remark", std::optional<std::string>> remark;
  };

  struct Course {
    rfl::Rename<"CID", sqlgen::PrimaryKey<int>> cid;
    rfl::Rename<"CName", std::string> cname;
    rfl::Rename<"Term", std::optional<int>> term = 1;
    rfl::Rename<"CTime", std::optional<int>> ctime;
    rfl::Rename<"Credit", float> credit = 0.0f;
  };

  struct Score {
    rfl::Rename<"SNo", std::string> sno;
    rfl::Rename<"CID", int> cid;
    rfl::Rename<"Score", std::optional<float>> score;
  };

  void design_eas_database() {
    auto db = sqlgen::Database<sqlgen::sqlite::Connection>("test_db.sqlite");

    // Create Student table
    auto student_table = sqlgen::Table<Student>(
        "Student",
        sqlgen::PrimaryKey{&Student::sno},
        sqlgen::Column{&Student::sno, "SNo", sqlgen::NotNull{}},
        sqlgen::Column{&Student::sname, "SName", sqlgen::NotNull{}},
        sqlgen::Column{&Student::sex, "Sex", sqlgen::Default{1}},
        sqlgen::Column{&Student::birthday, "Birthday", sqlgen::Null{}},
        sqlgen::Column{&Student::major, "Major", sqlgen::Null{}},
        sqlgen::Column{&Student::scorses, "Scorses", sqlgen::Default{0.0f}},
        sqlgen::Column{&Student::remark, "Remark", sqlgen::Null{}}
    );

    // Create Course table
    auto course_table = sqlgen::Table<Course>(
        "Course",
        sqlgen::PrimaryKey{&Course::cid},
        sqlgen::Column{&Course::cid, "CID", sqlgen::AutoIncrement{}, sqlgen::NotNull{}},
        sqlgen::Column{&Course::cname, "CName", sqlgen::NotNull{}},
        sqlgen::Column{&Course::term, "Term", sqlgen::Default{1}},
        sqlgen::Column{&Course::ctime, "CTime", sqlgen::Null{}},
        sqlgen::Column{&Course::credit, "Credit", sqlgen::NotNull{}, sqlgen::Default{0.0f}}
    );

    // Create Score table with composite primary key and foreign keys
    auto score_table = sqlgen::Table<Score>(
        "Score",
        sqlgen::PrimaryKey{&Score::sno, &Score::cid},
        sqlgen::Column{&Score::sno, "SNo", sqlgen::NotNull{}},
        sqlgen::Column{&Score::cid, "CID", sqlgen::NotNull{}},
        sqlgen::Column{&Score::score, "Score", sqlgen::Null{}},
        sqlgen::ForeignKey{&Score::sno}.References<Student>(&Student::sno),
        sqlgen::ForeignKey{&Score::cid}.References<Course>(&Course::cid)
    );

    // Create tables in database
    db.CreateTableIfNotExists(student_table);
    db.CreateTableIfNotExists(course_table);
    db.CreateTableIfNotExists(score_table);
  }

}
```

