  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    sqlite::Connection connection("test_db.sqlite");

    // 2. Create User and Post tables
    create_table(connection, User{});
    create_table(connection, Post{});

    // 3. Find users who have created at least one post between 2025-12-01 and 2025-12-31
    // Using the reference SQL logic with sqlgen's query builder
    auto query = select<ActiveUser>(
        distinct(u.user_id, u.username)
    ).from<User>(as(u))
     .join<Post>(as(p)).on(u.user_id == p.user_id)
     .where(p.created_at >= date("2025-12-01") && p.created_at <= date("2025-12-31"));

    // 4. Execute the query and return results
    return query.execute(connection);
}

}  // namespace query_active_users_posts
