  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.createTable<Customer>();
  conn.createTable<Product>();
  conn.createTable<Order>();
  conn.createTable<OrderItem>();

  // Execute the query using sqlgen's query builder
  auto results = conn.query<PurchaseHistory>(
    sqlgen::select(
      sqlgen::column<&Product::name>(),
      sqlgen::column<&Order::order_date>(),
      sqlgen::column<&OrderItem::quantity>()
    )
    .from<Customer>()
    .join<Order>(sqlgen::on<&Customer::customer_id, &Order::customer_id>())
    .join<OrderItem>(sqlgen::on<&Order::order_id, &OrderItem::order_id>())
    .join<Product>(sqlgen::on<&OrderItem::product_id, &Product::product_id>())
    .where(sqlgen::column<&Customer::customer_id>() == customer_id)
    .order_by(sqlgen::column<&Order::order_date>(), sqlgen::desc)
  );

  return results;
}

}  // namespace query_customer_purchase_history
