```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create SQLite connection
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Define aliases for the self-join
    auto e1 = alias<Employee>("e1");
    auto e2 = alias<Employee>("e2");

    // Build the query with LEFT JOIN for self-join
    auto query = read<std::vector<EmployeeManager>> |
                 from(e1) |
                 left_join(e2, on(e1.manager_id == e2.emp_id)) |
                 select(e1.name.as("employee"), e2.name.as("manager"));

    // Execute the query and return results
    return conn.execute(query);
}

}  // namespace query_employee_hierarchy
```

