Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_high_value_orders {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  // Connect to the SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Create the query using sqlgen's query builder
  using namespace sqlgen;

  // Build the query with JOIN, WHERE, and ORDER BY clauses
  auto query = Query<OrderView>{}
      .from<Order>()
      .join<Customer>(On<Order, Customer>(&Order::customer_id, &Customer::customer_id))
      .where(Where{}(&Order::total_amount > 1000))
      .order_by(OrderBy{&Order::total_amount, Order::DESC});

  // Execute the query and return results
  return sqlgen::sqlite::select(conn, query);
}

}  // namespace query_high_value_orders
```

