```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
                .and_then([](auto conn) {
                  // Add phone_number column
                  return sqlgen::execute(conn, "ALTER TABLE User ADD COLUMN phone_number VARCHAR(20);");
                })
                .and_then([](auto conn) {
                  // Add is_active column with default value
                  return sqlgen::execute(conn, "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1;");
                });

  return result.is_ok();
}

} // namespace schema_migration_add_column
```

This implementation:

1. Connects to the SQLite database "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. Uses the monadic `.and_then()` pattern to chain the ALTER TABLE operations
3. Executes two ALTER TABLE statements:
   - First adds the `phone_number` column as VARCHAR(20)
   - Then adds the `is_active` column as INTEGER with default value 1 (since SQLite doesn't have native boolean type)
4. Returns `true` if all operations succeed (result.is_ok()), or `false` if any operation fails

The error handling is built into the `sqlgen` library's `rfl::Result` type - if a column already exists or there are other SQL errors, the operations will fail gracefully and return `false`.

