```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then([&](auto conn) {
          // Start transaction
          return exec(conn, "BEGIN TRANSACTION");
      })
      .and_then([&](auto conn) {
          // Check if sender has sufficient funds and deduct amount
          return exec(conn, 
                     "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?", 
                     amount, from_account_id, amount);
      })
      .and_then([&](auto conn, auto update_result) {
          // Check if the first update was successful (affected 1 row)
          if (update_result.affected_rows() != 1) {
              // Rollback if insufficient funds
              return exec(conn, "ROLLBACK").and_then([](auto) { 
                  return std::make_pair(decltype(conn){}, false); 
              });
          }

          // Add amount to receiver
          return exec(conn, 
                     "UPDATE Account SET balance = balance + ? WHERE account_id = ?", 
                     amount, to_account_id)
              .and_then([&](auto conn, auto update_result2) {
                  // Check if second update was successful
                  if (update_result2.affected_rows() != 1) {
                      // Rollback if receiver account not found
                      return exec(conn, "ROLLBACK").and_then([](auto) { 
                          return std::make_pair(conn, false); 
                      });
                  }

                  // Commit transaction if both updates successful
                  return exec(conn, "COMMIT").and_then([](auto) { 
                      return std::make_pair(decltype(conn){}, true); 
                  });
              });
      })
      .and_then([](auto conn, bool success) {
          return success;
      })
      .value_or(false);

  return result;
}

}  // namespace transaction_transfer_funds
```

