namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
   using namespace sqlgen;

   // Connect to SQLite database
   SQLiteDB db("test_db.sqlite");

   // Update pending orders older than 7 days to expired
   int expired_count = db.update<Order>(
       set(&Order::status = "expired"),
       where(&Order::status == "pending" && 
             raw("order_date < DATE('now', '-7 days')"))
   );

   // Update shipped orders to delivered (simulating delivery confirmation)
   int delivered_count = db.update<Order>(
       set(&Order::status = "delivered"),
       where(&Order::status == "shipped")
   );

   // Return total number of rows affected
   return expired_count + delivered_count;
}

} // namespace update_order_status
```

