namespace upsert_user_profile {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Use INSERT OR REPLACE for upsert operation
  // This handles both insert and update scenarios in one operation
  auto result = conn->exec(
    "INSERT OR REPLACE INTO UserProfile (user_id, bio, avatar_url) VALUES (?, ?, ?)",
    u.user_id, 
    u.bio.value_or(""),  // Handle optional by providing default empty string
    u.avatar_url.value_or("")  // Handle optional by providing default empty string
  );

  // Check if the operation was successful
  return result.has_value();
}

} // namespace upsert_user_profile
```

Alternative implementation using sqlgen's fluent interface (if the raw SQL approach doesn't work with your version):

```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace upsert_user_profile {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  try {
    // First try to update the existing record
    auto update_result = conn->exec(
      "UPDATE UserProfile SET bio = ?, avatar_url = ? WHERE user_id = ?",
      u.bio.value_or(""),
      u.avatar_url.value_or(""),
      u.user_id
    );

    // If no rows were affected (user_id doesn't exist), insert new record
    if (update_result.value_or(0) == 0) {
      auto insert_result = conn->exec(
        "INSERT INTO UserProfile (user_id, bio, avatar_url) VALUES (?, ?, ?)",
        u.user_id,
        u.bio.value_or(""),
        u.avatar_url.value_or("")
      );
      return insert_result.has_value();
    }

    return true; // Update was successful
  } catch (const std::exception& e) {
    return false;
  }
}

} // namespace upsert_user_profile
```

The first implementation using `INSERT OR REPLACE` is more efficient and atomic, which is the preferred approach. The second implementation provides a fallback method that tries update first, then insert if needed.

Choose the first implementation unless you encounter issues with the `INSERT OR REPLACE` syntax in your specific version of `sqlgen`.

