```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create OrderItem table if it doesn't exist
  (create_table<OrderItem> | if_not_exists)(conn).value();

  // Insert the provided items into the table
  write(conn, items).value();

  // Define the SQL query with arithmetic operations for business metrics
  std::string query = R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) as discount_rate,
      COALESCE(tax_rate, 0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
      (unit_price * quantity / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
  )";

  // Execute the query and return the results
  auto metrics = read<std::vector<OrderMetrics>>(conn, query).value();
  return metrics;
}

}  // namespace calculate_order_metrics
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Creates the OrderItem table** if it doesn't exist using `create_table<OrderItem> | if_not_exists`
3. **Inserts the provided items** into the table using `sqlgen::write()`
4. **Executes the comprehensive SQL query** that performs all the required arithmetic operations:
   - Multiplication: `unit_price * quantity` for gross total
   - Division and subtraction: `(1 - discount_rate/100)` for discount application
   - Addition and multiplication: `(1 + tax_rate/100)` for tax calculation
   - Division: `total / quantity` for unit cost
   - Modulo: `quantity % 10` for quantity grouping
   - Multiplication: `unit_price * 0.3` for estimated profit
5. **Handles NULL values** using `COALESCE` to ensure all calculations work with default values when optional fields are null
6. **Returns the results** as a vector of `OrderMetrics` structures containing all the calculated business metrics

The function follows the same pattern as the code fragments from the repository, using the `sqlgen` library's monadic interface with `.value()` for error handling and the same table creation/insertion patterns shown in the test examples.

