```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    // Connect to database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create Account table
    conn.and_then(create_table<Account> | if_not_exists);

    // Insert some initial test data
    std::vector<Account> initial_accounts = {
        {.account_id = 1, .balance = 1000.0, .status = "active"},
        {.account_id = 2, .balance = 500.0, .status = "inactive"},
        {.account_id = 3, .balance = 2500.0, .status = "active"}
    };

    conn.and_then(insert(initial_accounts));

    // Update balances and statuses using set operations
    // Example 1: Update balance for account_id = 1
    conn.and_then(update<Account>()
                  .set("balance"_c = 1500.0)
                  .where("account_id"_c == 1));

    // Example 2: Update multiple columns using set with chaining
    conn.and_then(update<Account>()
                  .set("balance"_c = 750.0)
                  .set("status"_c = "suspended")
                  .where("account_id"_c == 2));

    // Example 3: Update based on condition with arithmetic operations
    conn.and_then(update<Account>()
                  .set("balance"_c = "balance"_c + 500.0)
                  .where("status"_c == "active"));

    // Verify changes persisted by reading the updated data
    auto updated_accounts = conn.and_then(read<std::vector<Account>>);

    // Check if updates were successful
    bool success = true;

    // Verify account_id 1 has balance 1500.0
    auto account1 = std::find_if(updated_accounts.begin(), updated_accounts.end(),
                                [](const Account& acc) { return acc.account_id == 1; });
    if (account1 != updated_accounts.end()) {
        success = success && (account1->balance == 1500.0);
    }

    // Verify account_id 2 has balance 750.0 and status "suspended"
    auto account2 = std::find_if(updated_accounts.begin(), updated_accounts.end(),
                                [](const Account& acc) { return acc.account_id == 2; });
    if (account2 != updated_accounts.end()) {
        success = success && (account2->balance == 750.0) && (account2->status == "suspended");
    }

    // Verify active accounts received the +500 bonus
    for (const auto& account : updated_accounts) {
        if (account.status == "active") {
            // Account 1 should be 1500 (was 1000, set to 1500, then +500 = 2000)
            // Account 3 should be 3000 (was 2500, +500 = 3000)
            if (account.account_id == 1) {
