Looking at the code fragments and the requirements, I need to implement a FULL JOIN between suppliers and products using the `sqlgen` library. Since SQLite doesn't natively support FULL JOIN, I'll need to simulate it using a combination of LEFT JOIN and UNION ALL.

Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = conn_result.value();

  // Since SQLite doesn't support FULL JOIN directly, we simulate it with:
  // LEFT JOIN (suppliers with products) UNION ALL RIGHT JOIN (products without suppliers)

  // First part: LEFT JOIN - all suppliers with their products (if any)
  auto left_join_query = 
    select("s.name"_c.as("supplier_name"), "p.name"_c.as("product_name"))
    .from<Supplier>("s")
    .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

  auto left_result = conn.and_then(left_join_query).and_then(read<std::vector<SupProd>>);
  if (!left_result) {
    return {};
  }
  auto left_join_results = left_result.value();

  // Second part: Products that don't have a matching supplier (RIGHT JOIN simulation)
  auto right_join_query = 
    select("NULL"_c.as("supplier_name"), "p.name"_c.as("product_name"))
    .from<Product>("p")
    .left_join<Supplier>("s").on("p.supplier_id"_c == "s.supplier_id"_c)
    .where("s.supplier_id"_c.is_null());

  auto right_result = conn.and_then(right_join_query).and_then(read<std::vector<SupProd>>);
  if (!right_result) {
    return left_join_results; // Return what we have so far
  }
  auto right_join_results = right_result.value();

  // Combine the results
  std::vector<SupProd> full_results;
  full_results.reserve(left_join_results.size() + right_join_results.size());
  full_results.insert(full_results.end(), left_join_results.begin(), left_join_results.end());
  full_results.insert(full_results.end(), right_join_results.begin(), right_join_results.end());

  return full_results;
}

}  // namespace full_join_suppliers_products
```

