```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn.and_then(create_table<Department> | if_not_exists)
      .and_then(create_table<Employee> | if_not_exists);

  // Insert department data
  for (const auto& dept : depts) {
    conn.and_then(insert_into(dept));
  }

  // Insert employee data
  for (const auto& emp : emps) {
    conn.and_then(insert_into(emp));
  }

  // Perform INNER JOIN
  auto inner_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id";

  auto inner_results = conn.and_then(sqlgen::execute(inner_join_query))
      .and_then(sqlgen::read<std::vector<std::tuple<std::string, std::string, std::string, double>>>);

  for (const auto& [dept_name, first_name, last_name, salary] : inner_results) {
    analysis.inner_join_results.push_back(JoinResult{
      .department_name = dept_name,
      .first_name = first_name,
      .last_name = last_name,
      .salary = salary
    });
  }

  // Perform LEFT JOIN
  auto left_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id";

  auto left_results = conn.and_then(sqlgen::execute(left_join_query))
      .and_then(sqlgen::read<std::vector<std::tuple<std::optional<std::string>, std::string, std::string, double>>>);

  for (const auto& [dept_name, first_name, last_name, salary] : left_results) {
    analysis.left_join_results.push_back(JoinResult{
      .department_name = dept_name,
      .first_name = first_name,
      .last_name = last_name,
      .salary = salary
    });
  }

  // Perform RIGHT JOIN (simulated with LEFT JOIN since SQLite doesn't support RIGHT JOIN)
  auto right_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  auto right_results = conn.and_then(sqlgen::execute(right_join_query))
      .and_then(sqlgen::read<std::vector<std::tuple<std::string, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);

  for (const auto& [dept_name, first_name, last_name, salary] : right_results) {
    analysis.right_join_results.push_back(JoinResult{
      .department_name = dept_name,
      .first_name = first_name,
      .last_name = last_name,
      .salary = salary
    });
  }

  // Perform FULL JOIN (simulated with UNION of LEFT and RIGHT joins)
  auto full_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  auto full_results = conn.and_then(sqlgen::execute(full_join_query))
      .and_then(sqlgen::read<std::vector<std::tuple<std::optional<std::string>, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);

  for (const auto& [dept_name, first_name, last_name, salary] : full_results) {
    analysis.full_join_results.push_back(JoinResult{
      .department_name = dept_name,
      .first_name = first_name,
      .last_name = last_name,
      .salary = salary
    });
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to SQLite database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Creates tables** for Department and Employee using `create_table` with `if_not_exists` option
3. **Inserts data** from the input vectors into the respective tables
4. **Performs all four join types**:
   - **INNER JOIN**: Gets employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even without departments)
   - **RIGHT JOIN**: Simulated using LEFT JOIN (since SQLite doesn't support RIGHT JOIN natively)
   - **FULL JOIN**: Simulated using UNION of LEFT and RIGHT joins
5. **Returns comprehensive analysis** with results from all join operations stored in the `JoinAnalysis` structure

The code handles optional values properly using `std::optional` to accommodate cases where joins may result in NULL values from either table.

