inline auto concat_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query using CONCAT function to combine first_name and last_name
    return select<"CONCAT(first_name, ' ', last_name) as full_name">(from<Person>);
}

}  // namespace concat_function
