Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Database::open("test_db.sqlite");

  // Build the query to extract weekday and aggregate totals
  using namespace sqlgen;
  auto query = select(
      sqlite::strftime("%w", &Sales::sale_time).as("weekday"),
      sum(&Sales::quantity).as("total_quantity")
  ).from<Sales>().group_by("weekday");

  // Execute the query and get results
  auto results = db.query(query);

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    stats.push_back(WeekdayStats{
      .weekday = std::stoi(row.at("weekday")),
      .total_quantity = std::stoi(row.at("total_quantity"))
    });
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

