```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace update_with_arithmetic {

struct Player {
  sqlgen::PrimaryKey<int> id;
  int score;
};

/**
 * This function demonstrates updating a column with arithmetic.
 * Returns: std::string.
 */
inline std::string update_with_arithmetic() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create an update query with arithmetic operation
    auto update_query = update<Player>().set("score"_c = "score"_c + 10);

    // Convert the query to SQL string
    return sqlgen::sqlite::to_sql(update_query);
}

}  // namespace update_with_arithmetic
```

