#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create a SELECT query that filters Source records where value > 100
    // and projects only the 'value' field to match the Target structure
    auto select_query = select("value"_c).from<Source>().where("value"_c > 100);

    // Create the CREATE TABLE AS SELECT statement
    return create_table<Target>().as(select_query);
}

}  // namespace create_table_as_select
```

